CREATE TABLE `student_organization` (`id` varchar(36) NOT NULL,`tenant_id` varchar(36) NOT NULL,`name` varchar(150) NOT NULL,`normalized_name` varchar(150) NOT NULL,`abbreviation` varchar(30),`code` varchar(30) NOT NULL,`normalized_code` varchar(30) NOT NULL,`description` text,`founding_date` date,`secretariat_location_id` varchar(36),`archived` boolean NOT NULL DEFAULT false,`archived_at` timestamp(3),`archive_reason` varchar(1000),`version` int NOT NULL DEFAULT 1,`created_at` timestamp(3) NOT NULL,`updated_at` timestamp(3) NOT NULL,PRIMARY KEY (`id`),UNIQUE KEY `student_organization_tenant_id_unique` (`tenant_id`,`id`),UNIQUE KEY `student_organization_tenant_code_unique` (`tenant_id`,`normalized_code`),CONSTRAINT `student_organization_tenant_fkey` FOREIGN KEY (`tenant_id`) REFERENCES `tenant` (`id`),CONSTRAINT `student_organization_location_fkey` FOREIGN KEY (`tenant_id`,`secretariat_location_id`) REFERENCES `location` (`tenant_id`,`id`),CONSTRAINT `student_organization_version_check` CHECK (`version` > 0));
CREATE INDEX `student_organization_tenant_archive_name_idx` ON `student_organization` (`tenant_id`,`archived`,`normalized_name`);
CREATE TABLE `organization_period` (`id` varchar(36) NOT NULL,`tenant_id` varchar(36) NOT NULL,`organization_id` varchar(36) NOT NULL,`name` varchar(100) NOT NULL,`status` enum('planned','active','completed') NOT NULL DEFAULT 'planned',`start_date` date NOT NULL,`end_date` date NOT NULL,`version` int NOT NULL DEFAULT 1,`created_at` timestamp(3) NOT NULL,`updated_at` timestamp(3) NOT NULL,PRIMARY KEY (`id`),UNIQUE KEY `organization_period_tenant_id_unique` (`tenant_id`,`id`),CONSTRAINT `organization_period_organization_fkey` FOREIGN KEY (`tenant_id`,`organization_id`) REFERENCES `student_organization` (`tenant_id`,`id`),CONSTRAINT `organization_period_range_check` CHECK (`end_date` >= `start_date`));
CREATE INDEX `organization_period_history_idx` ON `organization_period` (`tenant_id`,`organization_id`,`start_date`);
CREATE TABLE `organization_membership` (`id` varchar(36) NOT NULL,`tenant_id` varchar(36) NOT NULL,`organization_id` varchar(36) NOT NULL,`student_id` varchar(36) NOT NULL,`started_at` date NOT NULL,`ended_at` date,`reason` varchar(1000) NOT NULL,`created_by_user_id` varchar(36) NOT NULL,`created_at` timestamp(3) NOT NULL,PRIMARY KEY (`id`),CONSTRAINT `organization_membership_organization_fkey` FOREIGN KEY (`tenant_id`,`organization_id`) REFERENCES `student_organization` (`tenant_id`,`id`),CONSTRAINT `organization_membership_student_fkey` FOREIGN KEY (`tenant_id`,`student_id`) REFERENCES `student_profile` (`tenant_id`,`id`),CONSTRAINT `organization_membership_actor_fkey` FOREIGN KEY (`tenant_id`,`created_by_user_id`) REFERENCES `user` (`tenant_id`,`id`),CONSTRAINT `organization_membership_range_check` CHECK (`ended_at` IS NULL OR `ended_at` >= `started_at`));
CREATE INDEX `organization_membership_history_idx` ON `organization_membership` (`tenant_id`,`organization_id`,`student_id`,`started_at`);
CREATE TABLE `organization_leadership` (`id` varchar(36) NOT NULL,`tenant_id` varchar(36) NOT NULL,`period_id` varchar(36) NOT NULL,`student_id` varchar(36) NOT NULL,`position_name` varchar(100) NOT NULL,`normalized_position_name` varchar(100) NOT NULL,`allows_multiple_holders` boolean NOT NULL,`started_at` date NOT NULL,`ended_at` date,`reason` varchar(1000) NOT NULL,`created_by_user_id` varchar(36) NOT NULL,`created_at` timestamp(3) NOT NULL,PRIMARY KEY (`id`),CONSTRAINT `organization_leadership_period_fkey` FOREIGN KEY (`tenant_id`,`period_id`) REFERENCES `organization_period` (`tenant_id`,`id`),CONSTRAINT `organization_leadership_student_fkey` FOREIGN KEY (`tenant_id`,`student_id`) REFERENCES `student_profile` (`tenant_id`,`id`),CONSTRAINT `organization_leadership_actor_fkey` FOREIGN KEY (`tenant_id`,`created_by_user_id`) REFERENCES `user` (`tenant_id`,`id`),CONSTRAINT `organization_leadership_range_check` CHECK (`ended_at` IS NULL OR `ended_at` >= `started_at`));
CREATE INDEX `organization_leadership_history_idx` ON `organization_leadership` (`tenant_id`,`period_id`,`normalized_position_name`,`started_at`);
CREATE TABLE `organization_event` (`id` varchar(36) NOT NULL,`tenant_id` varchar(36) NOT NULL,`organization_id` varchar(36) NOT NULL,`period_id` varchar(36),`relationship_id` varchar(36),`actor_user_id` varchar(36) NOT NULL,`operation` varchar(50) NOT NULL,`effective_date` date,`reason` varchar(1000) NOT NULL,`occurred_at` timestamp(3) NOT NULL,PRIMARY KEY (`id`),CONSTRAINT `organization_event_organization_fkey` FOREIGN KEY (`tenant_id`,`organization_id`) REFERENCES `student_organization` (`tenant_id`,`id`),CONSTRAINT `organization_event_period_fkey` FOREIGN KEY (`tenant_id`,`period_id`) REFERENCES `organization_period` (`tenant_id`,`id`),CONSTRAINT `organization_event_actor_fkey` FOREIGN KEY (`tenant_id`,`actor_user_id`) REFERENCES `user` (`tenant_id`,`id`));
CREATE INDEX `organization_event_history_idx` ON `organization_event` (`tenant_id`,`organization_id`,`occurred_at`);
